PROCEDURE VulnerableDH()
 // Generate public parameters
 p ← LARGE_PRIME()
 g ← PRIMITIVE_ROOT(p)

 // Alice's keys
 a ← RANDOM(2, p-2)
 AlicePub ← POW(g, a, p)

 // Bob's keys
 b ← RANDOM(2, p-2)
 BobPub ← POW(g, b, p)

 // Oscar intercepts!
 o ← RANDOM(2, p-2)
 OscarPub ← POW(g, o, p)

 // Oscar replaces Bob's public value with his own
 AliceShared ← POW(OscarPub, a, p) // Alice thinks this is shared with Bob

 // Oscar replaces Alice's public value with his own 
 BobShared ← POW(OscarPub, b, p) // Bob thinks this is shared with Alice

 // Both equal to g^(a*o) mod p or g^(b*o) mod p
 // Alice and Bob NEVER share a key directly!

 RETURN AliceShared, BobShared
END PROCEDURE

PROCEDURE STS_KeyExchange(Alice, Bob)
 // Parameters
 p ← LARGE_PRIME()
 g ← PRIMITIVE_ROOT(p)

 // Alice generates ephemeral key pair
 a ← RANDOM(2, p-2)
 gA ← POW(g, a, p)

 // Bob generates ephemeral key pair
 b ← RANDOM(2, p-2)
 gB ← POW(g, b, p)

 // Exchange public values WITH certificates
 CertA ← GET_CERTIFICATE(Alice)
 CertB ← GET_CERTIFICATE(Bob)

 // Signatures prevent MITM
 SigA ← SIGN(AlicePrivate, gA || gB)
 SigB ← SIGN(BobPrivate, gB || gA)

 // Verify certificates AND signatures
 IF NOT VERIFY_CERT(CertA) THEN ABORT
 IF NOT VERIFY_CERT(CertB) THEN ABORT
 IF NOT VERIFY_SIG(SigA, AlicePublic, gA || gB) THEN ABORT
 IF NOT VERIFY_SIG(SigB, BobPublic, gB || gA) THEN ABORT

 // Only now compute shared secret
 K ← POW(gB, a, p) // Alice computes
 // Bob computes: POW(gA, b, p)
 // Both equal g^(ab) mod p, attacker cannot substitute

 RETURN K
END PROCEDURE
